from flask import Flask, render_template, request
import random, pprint

app = Flask(__name__)

@app.route('/')
def index():
    return 'hello world!'

@app.route('/hello')
def hello():
    return '반갑습니다!!'

@app.route('/greeting/<name>')
def greeting(name):
    return f'반갑습니다! {name}님!'

@app.route('/cube/<int:num>')
def cube(num):
    result = num ** 3
    return str(result)

# '/lunch/3' 으로 요청이 들어왔을 때
# 메뉴 리스트에서 랜덤으로 인원 수 만큼 메뉴 골라서
# 출력해주기
@app.route('/lunch/<int:people>')
def lunch(people):
    menu = ['짜장면', '짬뽕', '김밥', '쫄면', '돈까스']
    order = random.sample(menu, people)
    return str(order)

@app.route('/html_tag')
def html_tag():
    return '<h1>안녕하세요!!</h1>'

@app.route('/html_line')
def html_line():
    return """
    <h1>여러 줄 보내기</h1>
    <ul>
        <li>1번</li>
        <li>2번</li>
    </ul>
    """

@app.route('/html_render')
def html_render():
    return render_template('index.html')

@app.route('/html_name/<name>')
def html_name(name):
    return render_template('hello.html', name=name)

@app.route('/math/<int:num>')
def math(num):
    result = num ** 3
    return render_template('math.html', num=num, result=result)

# 저녁 메뉴 랜덤 뽑기
# '/dinner' 로 요청이 들어왔을 때
# 저녁 메뉴에서 랜덤으로 하나를 뽑아서 이미지와 메뉴 이름을 응답해주자.
# 출력 예시
# 오늘의 저녁은 ??? 입니다.
# ??? 이미지
@app.route('/dinner')
def dinner():
    menu = {
        '초밥' : 'data:image/jpeg;base64,',
        '탕수육': 'data:image/jpeg;base64,',
        '스테이크' : 'data:image/jpeg;base64,'
    }

    pick = random.choice(list(menu.keys()))
    #url = menu['짜장면'] # key error
    url = menu.get(pick) # none
    return render_template('dinner.html', pick=pick, url=url)

@app.route('/lotto')
def lotto():
    number_list = list(range(1, 46))
    lucky = random.sample(number_list, 6)
    return render_template('lotto.html', lucky=lucky)

@app.route('/naver')
def naver():
    return render_template('naver.html')

@app.route('/ping')
def ping():
    return render_template('ping.html')

@app.route('/pong')
def pong():
    username = request.args.get('name')
    print(request.args)
    return render_template('pong.html', username=username)

@app.route('/ping_new')
def ping_new():
    return render_template('ping_new.html')

@app.route('/pong_new', methods=['POST'])
def pong_new():
    username = request.form.get('name')
    print(request.args)
    return render_template('pong_new.html', username=username)

@app.route('/about_you', methods=['GET'])
def about_you():
    return render_template('about_you.html')

@app.route('/about_you_result', methods=['POST'])
def about_you_result():
    username = request.form.get('name')
    age = request.form.get('age')
    user = {}
    character = ['인성', '의리', '자상함', '멋짐', '잘생김', '못생김', '외로움', '똑똑함']
    action = ['을 많이 넣자', '을 조금 넣자', '을 살짝 넣자', '은 넣지 말자']

    user["username"] = username
    user["age"] = age
    user["character"] = random.choice(character)
    user["action"] = random.choice(action)

    return render_template('about_you_result.html', user=user)

# 이 파이썬 파일이 직접 실행된 코드라면 if 문 코드를 동작한다.
if __name__ == '__main__':
    app.run(debug=True)